"""
MKT Original Commentary — 1 John chapter 5
Run: python3 scripts/zc-original-1john-5-5.py

Source data used:
- data/interlinear/1john.json
- data/translation/glossary-greek.json (G4102 πίστις dispute_level=3; G166 αἰώνιος dispute_level=3;
  G2222 ζωή dispute_level=2; G4151 πνεῦμα dispute_level=3)
- data/translation/notes/1john.json
- data/translation/draft/mediating/1john.json (MKT text)
- scripts/mkt-1john-4-5.py (prior translation decisions carried forward)

Key decisions in this range:
- G26 ἀγάπη: covenantal, willed "love" — consistent with ch.4 usage.
- G166 αἰώνιος: "eternal" in standard rendering; glossed as "age-to-come life" at vv.11,13,20
  where the quality of resurrection life (not mere duration) is the point.
- G4151 πνεῦμα: "Spirit" (capitalised) for the Holy Spirit in vv.6–8.
- G4190 ὁ πονηρός: "the evil one" throughout — personal, with definite article.
- G5547 τὸν Χριστόν: "the Christ" — the article is present in Greek, carrying full messianic weight.
- Comma Johanneum (5:7): absent from all pre-14th c. Greek manuscripts; not original; translation
  follows UBS5/NA28. Commentary note required at v.7.
- "Sin unto death" (5:16): the referent is not specified by John and is deliberately left unresolved.
- 5:20 οὗτος: demonstrative points to the nearest antecedent (Jesus Christ) — direct identification
  of Jesus as "the true God and eternal life" is the reading adopted.
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JOHN1 = {
  "5": {
    "1": '<p><strong>πᾶς ὁ πιστεύων</strong> — "everyone believing" (present participle) makes faith an ongoing orientation, not a completed past event. The perfect <strong>γεγέννηται</strong> ("has been born") marks a completed birth whose result stands permanently.</p><p><strong>τὸν Χριστόν</strong> — the article makes this "the Christ," the full messianic title. John is insisting on the specific identification: Jesus is the Messiah, the anointed one Israel awaited — not a generic divine figure.</p><p><strong>ἐκ τοῦ θεοῦ γεγέννηται … τὸν γεγεννημένον ἐξ αὐτοῦ</strong> — family logic: love for the Father necessarily extends to the children born of him. Horizontal love for fellow believers is grounded in shared vertical origin in God, not in personal affinity.</p>',
    "2": '<p><strong>γινώσκομεν</strong> — present tense: "we know" — ongoing, repeatable recognition. The verse reverses the verification direction of v.1: there, love for the Father was inferred from love for his children; here, love for the children is verified by love for God and obedience to his commands.</p><p><strong>τηρῶμεν τὰς ἐντολὰς αὐτοῦ</strong> — G5083 <em>tēréō</em> means to guard or keep watch over — active custody, not casual observance. G1785 <em>entolḗ</em> = authoritative mandate, the language of royal or divine decree rather than general advice.</p>',
    "3": '<p><strong>αὕτη γάρ ἐστιν ἡ ἀγάπη τοῦ θεοῦ</strong> — subjective genitive: "love for God" consists in this — command-keeping. John defines love as enacted allegiance, not felt warmth. G26 <em>agápē</em> throughout the letter is covenantal, willed, self-giving.</p><p><strong>βαρεῖαι οὐκ εἰσίν</strong> — G926 <em>barýs</em> means "heavy" (cf. the root behind "burden"). The claim is not that obedience is effortless but that the commands do not crush. John\'s implicit argument (v.4 supplies the reason): the one born of God has the overcomer\'s resources.</p>',
    "4": '<p><strong>πᾶν τὸ γεγεννημένον ἐκ τοῦ θεοῦ</strong> — neuter singular ("everything born of God") is more expansive than a masculine plural: the overcoming property belongs to the entire class of those born of God without exception.</p><p><strong>νικᾷ τὸν κόσμον</strong> — G3528 <em>nikáō</em> present tense: "overcomes" as an ongoing, habitual reality. The aorist in the next clause (<strong>ἡ νίκη ἡ νικήσασα τὸν κόσμον</strong>) points to a decisive past victory that grounds the present — the victory already won that continues to be enacted.</p><p><strong>ἡ πίστις ἡμῶν</strong> — the double article isolates "our faith" (G4102 <em>pístis</em>, dispute_level 3) as the specific instrument of victory. <em>Pístis</em> spans "belief" and "faithfulness/reliant trust"; here the context (active overcoming, directed against the world) favors committed trust rather than propositional assent alone.</p>',
    "5": '<p><strong>τίς ἐστιν ὁ νικῶν τὸν κόσμον</strong> — a rhetorical question with a single, exclusive answer. The present participle <em>ὁ νικῶν</em> ("the one overcoming") sustains the present-tense emphasis of v.4: overcoming is not a past credential but a present reality.</p><p><strong>εἰ μὴ ὁ πιστεύων ὅτι Ἰησοῦς ἐστιν ὁ υἱὸς τοῦ θεοῦ</strong> — "except the one believing that Jesus is the Son of God." G4100 <em>pisteúō</em> with <em>ὅτι</em> + content: belief that Jesus (the human name) *is* the Son of God (the high confessional title). John insists on the full identification against any Christology that would separate the earthly Jesus from the divine Son.</p>',
    "6": '<p><strong>ὁ ἐλθὼν δι᾽ ὕδατος καὶ αἵματος</strong> — Jesus came "through water and blood" (G5204, G129). The most defensible reading identifies the water with his baptism (the inauguration of ministry) and the blood with his death. "Not by water only but by water and blood" directly counters an early error — possibly associated with Cerinthus — in which the divine Christ entered Jesus at baptism but departed before the crucifixion, leaving only the human to die. John insists the same person encompassed both.</p><p><strong>τὸ πνεῦμά ἐστιν τὸ μαρτυροῦν</strong> — the Spirit is continuously testifying (present participle). The reason: <strong>ὅτι τὸ πνεῦμά ἐστιν ἡ ἀλήθεια</strong> — the Spirit does not merely speak truth; the Spirit <em>is</em> truth (G225 <em>alḗtheia</em>), making the Spirit\'s testimony self-validating in a way human testimony cannot be.</p>',
    "7": '<p>The verse reads simply: <strong>ὅτι τρεῖς εἰσιν οἱ μαρτυροῦντες</strong> — "For there are three that testify." This is the entire authentic text of 5:7; the sentence continues at 5:8 with the three witnesses.</p><p>The expanded reading inserted in some late manuscripts and the Textus Receptus — adding "in heaven: the Father, the Word, and the Holy Spirit, and these three are one" — is known as the <em>Comma Johanneum</em>. It is absent from every Greek manuscript predating the 14th century, from the Vulgate\'s earliest manuscripts, and from all patristic citations of this passage through the fifth century. Erasmus excluded it; the critical text (UBS5/NA28) omits it. The MKT translation follows the critical text.</p>',
    "8": '<p><strong>τὸ πνεῦμα καὶ τὸ ὕδωρ καὶ τὸ αἷμα</strong> — the three witnesses each carry the definite article, individuating them. The Spirit testifies in the present (v.6); the water and blood are historical markers — the baptism and crucifixion — that continue to bear testimony because of what they established.</p><p><strong>εἰς τὸ ἕν εἰσιν</strong> — literally "into the one they are" — they converge toward a single testimony. The phrase does not assert numerical unity of the witnesses but the coherence and agreement of their testimony. The legal principle behind this (Deut 19:15: two or three witnesses establish a matter) is invoked: three witnesses, one verdict, establishing the truth about Jesus Christ.</p>',
    "9": '<p><strong>τὴν μαρτυρίαν τῶν ἀνθρώπων λαμβάνομεν</strong> — G3141 <em>martyría</em> is legal testimony. G444 <em>ánthrōpos</em> (human being) used generically: we routinely accept human testimony in courts and daily life as establishing facts.</p><p><strong>ἡ μαρτυρία τοῦ θεοῦ μείζων ἐστίν</strong> — G3187 <em>meízōn</em>, greater: a fortiori argument. If lesser (human) testimony is accepted, how much more the greater (divine). The argument is specific, not general: <strong>αὕτη ἐστὶν ἡ μαρτυρία τοῦ θεοῦ ἣν μεμαρτύρηκεν περὶ τοῦ υἱοῦ αὐτοῦ</strong> — the perfect <em>memartyréken</em> ("has testified") means this testimony has been given and now stands on record.</p>',
    "10": '<p><strong>ὁ πιστεύων εἰς τὸν υἱὸν τοῦ θεοῦ ἔχει τὴν μαρτυρίαν ἐν ἑαυτῷ</strong> — G4100 with εἰς + accusative: directed, committed trust "into" the Son, not mere acknowledgment about him. The testimony becomes internal — <em>en heautō</em>, "in himself" — the believer has internalized the divine attestation.</p><p><strong>πεποίηκεν αὐτὸν ψεύστην</strong> — perfect tense: "has made him a liar" — a standing charge, not a momentary failure. G5583 <em>pseústēs</em> (liar): the one who rejects God\'s testimony effectively calls God a fabricator. The starkness is deliberate — there is no neutral position between trusting God\'s witness and impugning it.</p>',
    "11": '<p><strong>ζωὴν αἰώνιον ἔδωκεν ἡμῖν ὁ θεός</strong> — G2222 <em>zōḗ</em> (dispute_level 2) with G166 <em>aiṓnios</em> (dispute_level 3). <em>Aiṓnios</em> derives from <em>aiṓn</em> (age/era): the life proper to the coming age, resurrection life — not simply "life that lasts forever" but the mode of existence belonging to God\'s new creation. Duration is implied; the primary sense is qualitative.</p><p><strong>αὕτη ἡ ζωὴ ἐν τῷ υἱῷ αὐτοῦ ἐστίν</strong> — this life is located <em>in</em> the Son, not distributed independently of him. The implication in v.12 follows necessarily: union with the Son is the only access to the life.</p>',
    "12": '<p><strong>ὁ ἔχων τὸν υἱὸν ἔχει τὴν ζωήν</strong> — G2192 <em>échō</em> ("to have") in both clauses: possession of the Son is possession of life; absence is absence. The antithesis is stark with no middle term. John does not say "the one who knows about the Son" or "the one who admires the Son" — the verb is <em>have</em>.</p><p>The second clause adds <strong>τοῦ θεοῦ</strong> — "the Son of God" — elevating the title to make refusal explicit: to not have the Son is to not have the Son <em>of God</em>, the one in whom the life resides by divine appointment (v.11).</p>',
    "13": '<p><strong>ἔγραψα ὑμῖν … ἵνα εἰδῆτε</strong> — G1492 <em>oîda</em> (from which <em>eídēte</em> derives) denotes settled, perceptual knowledge — knowledge one already holds, not the process of coming to know (which is G1097 <em>ginṓskō</em>). John\'s purpose is certainty, not information transfer.</p><p><strong>τοῖς πιστεύουσιν εἰς τὸ ὄνομα τοῦ υἱοῦ τοῦ θεοῦ</strong> — believers "into the name" — directional trust committed to the name as the full revelation of who Jesus is. The epistle has throughout probed whether the readers\' faith is genuine; this closing purpose statement assures rather than threatens.</p>',
    "14": '<p><strong>παρρησία</strong> (G3954) — in classical Athens, the citizen\'s right of free speech before the assembly; transferred to address God. In prayer, it means filial boldness — not presumption but the confidence of those who approach through the Son.</p><p><strong>ἐάν τι αἰτώμεθα κατὰ τὸ θέλημα αὐτοῦ</strong> — present subjunctive <em>aitōmetha</em> = "whenever we ask" — a repeatable condition. <strong>κατὰ τὸ θέλημα αὐτοῦ</strong> is not a limiting escape clause but the governing channel: G2307 <em>thélēma</em> is the sovereign, purposive will, not a mood that might be guessed at. The assurance and the limit belong together.</p>',
    "15": '<p><strong>ἐὰν οἴδαμεν ὅτι ἀκούει ἡμῶν</strong> — G1492 again: settled certainty that he hears us. <strong>ἀκούει</strong> is attentive hearing — God listening with regard to what is asked, not mere acoustic reception.</p><p><strong>οἴδαμεν ὅτι ἔχομεν τὰ αἰτήματα</strong> — G155 <em>aitēmata</em>, the specific requests as formulated. The second <em>oídamen</em> draws the inference: given the first certainty (he hears), the second follows (we have the petitions). The present <em>échomen</em> ("we have") is bold — not "we will eventually receive" but "we hold" — since the hearing God has already engaged the request.</p>',
    "16": '<p><strong>ἁμαρτάνοντα ἁμαρτίαν μὴ πρὸς θάνατον</strong> — two words: the verb G264 <em>hamartánō</em> (to sin) and the noun G266 <em>hamartía</em> (the sin). "Sinning a sin not toward death" — a specific sin that does not carry the characteristic of moving toward death.</p><p><strong>αἰτήσει καὶ δώσει αὐτῷ ζωήν</strong> — G2065 <em>erōtáō</em> (ask/pray) rather than G154 <em>aitéō</em>; <em>erōtáō</em> carries slight intimacy — the asking of one who is near. The promise: intercession for a sinning brother will result in God granting life to that person.</p><p><strong>ἔστιν ἁμαρτία πρὸς θάνατον· οὐ περὶ ἐκείνης λέγω ἵνα ἐρωτήσῃ</strong> — John does not identify the sin-unto-death; the phrase has generated extensive debate (apostasy? blasphemy against the Spirit? definitive unbelief? persistent rejection of the Son?). John deliberately withholds specification. The withdrawal of the intercession mandate ("I am not saying he should pray about that") is unusual — the text leaves it without explanation and commentary should not supply one.</p>',
    "17": '<p><strong>πᾶσα ἀδικία ἁμαρτία ἐστίν</strong> — G93 <em>adikía</em> (unrighteousness/injustice) is the wider moral category; every instance of it is G266 <em>hamartía</em>. The statement prevents a minimizing reading: nothing in the moral domain is morally neutral.</p><p><strong>καὶ ἔστιν ἁμαρτία οὐ πρὸς θάνατον</strong> — the qualifying counterclaim: not every sin is the death-kind. V.17 contextualises vv.14–16: the intercessory promise stands for the ordinary domain of Christian struggle; the existence of a sin-unto-death does not nullify the prayer mandate for sins that do not fall in that category.</p>',
    "18": '<p><strong>πᾶς ὁ γεγεννημένος ἐκ τοῦ θεοῦ οὐχ ἁμαρτάνει</strong> — the perfect passive participle "having been born of God" with present "does not sin" — a completed-state and its ongoing implication. This is not a claim of sinless perfection (cf. 1:8–10, 2:1) but of habitual orientation: the defining direction of the life born of God is not sin.</p><p><strong>ὁ γεννηθεὶς ἐκ τοῦ θεοῦ τηρεῖ αὐτόν</strong> — the grammatical subject shifts: <em>ὁ γεννηθεὶς ἐκ τοῦ θεοῦ</em> (aorist passive singular, "the one born of God") most naturally refers to the Son — Jesus Christ — as the guardian of believers. The believer does not achieve non-sinning by effort; the Son guards them.</p><p><strong>ὁ πονηρός</strong> — G4190 with definite article: "the evil one" (personal). G680 <em>háptō</em> in the middle = to take hold of, to grasp — the evil one cannot lay hands on the one under the Son\'s protection.</p>',
    "19": '<p><strong>ἐκ τοῦ θεοῦ ἐσμεν</strong> — "we are of God" — origin and belonging stated as settled knowledge. This grounds the contrast that follows.</p><p><strong>ὁ κόσμος ὅλος ἐν τῷ πονηρῷ κεῖται</strong> — G2749 <em>keîtai</em> = "lies." The verb describes passive, inert lying — the world does not struggle against the evil one; it lies in his grip as one who has surrendered. G2889 <em>kósmos</em> here is the world-system ordered apart from God. The contrast with believers (who are "of God" and guarded, v.18) is stark and deliberate.</p>',
    "20": '<p><strong>ὁ υἱὸς τοῦ θεοῦ ἥκει</strong> — G2240 <em>hḗkō</em> is a perfect-like present: "has come and is here" — arrival with present consequence. The Son of God\'s coming is not merely past history but an ongoing present reality.</p><p><strong>δέδωκεν ἡμῖν διάνοιαν</strong> — G1271 <em>diánoia</em>, not merely G3563 <em>noûs</em>: the capacity for reflective, discerning understanding — moral and spiritual perception. The perfect <em>dédōken</em> ("has given") marks a completed gift now possessed.</p><p><strong>τὸν ἀληθινόν</strong> — G228 <em>alēthinós</em> = "the Real/Genuine One" (distinct from G227 <em>alēthḗs</em> = "accurate/truthful"). The True One in the sense of ultimate ontological reality — everything else is shadow or substitute. The repetition emphasises identification: we are <em>in</em> the True One.</p><p><strong>οὗτός ἐστιν ὁ ἀληθινὸς θεὸς καὶ ζωὴ αἰώνιος</strong> — "this one is the true God and eternal life." The demonstrative <em>οὗτος</em> points to the nearest antecedent — Jesus Christ, named in the preceding clause. This is the letter\'s most explicit Christological predication: Jesus Christ is the true God; Jesus Christ is eternal life (cf. v.11: "the life is in his Son"; Jn 14:6; Jn 20:28).</p>',
    "21": '<p><strong>Τεκνία</strong> — diminutive of <em>téknon</em> (child), used throughout 1 John with characteristic intimacy: "little children." The pastoral warmth of the address heightens the urgency of the command that follows.</p><p><strong>φυλάξατε ἑαυτοὺς ἀπὸ τῶν εἰδώλων</strong> — G5442 <em>phylássō</em> aorist imperative: "guard yourselves" — a sharp, decisive act, not a gradual process. The aorist implies urgency: do it now, decisively. G1497 <em>eídōlon</em> = idol, any substitute for the true God. The abruptness is deliberate: after a sustained argument identifying what and who is genuinely real (vv.18–20), the counter is not engagement with idols but active self-protection against them.</p>'
  }
}


def main():
    existing = load_comm('mkt-original', '1john')
    merge_comm(existing, JOHN1)
    save_comm('mkt-original', '1john', existing)
    print('1 John 5 mkt-original written.')

if __name__ == '__main__':
    main()
